def compact_log_message_for_display(message: str) -> str | None:
    """把底层运行日志压缩成面向任务页的简洁状态日志；返回 None 表示不显示。"""
    msg = str(message or "").strip()
    if not msg:
        return None
    # 日志已经按任务页隔离，界面内不再重复显示 [任务1] 这类前缀。
    msg = re.sub(r"^\[任务\d+\]\s*", "", msg).strip()
    if not msg:
        return None
    if not COMPACT_LOG_MODE:
        return msg

    # 关键错误/警告必须保留。
    if COMPACT_LOG_CRITICAL_RE.search(msg):
        return msg

    m = re.search(r"已启动书籍按章流程，共选中\s*(\d+)\s*个章节", msg)
    if m:
        return f"🚀 已开始：{m.group(1)} 个章节。"
    m = re.search(r"开始按章流水线处理，共选中\s*(\d+)\s*个章节", msg)
    if m:
        return f"🚀 已开始：{m.group(1)} 个章节。"
    m = re.search(r"开始处理章节 \[(\d+/\d+)\]: \[(.*?)\]", msg)
    if m:
        return f"▶ 章节 {m.group(1)}：{m.group(2).strip()}"
    m = re.search(r"章节完成 \[(\d+/\d+)\]\s*(.*?)：总用时\s*(.*?)（状态：([^）]+)）", msg)
    if m:
        status = m.group(4).strip()
        mark = "✅" if status == "完成" else "⏹️"
        return f"{mark} 章节 {m.group(1)} {status}：用时 {m.group(3).strip()}。"
    m = re.search(r"按章流水线结束。总用时：([^。]+)", msg)
    if m:
        return f"🎉 全部完成：总用时 {m.group(1).strip()}。"
    m = re.search(r"配图状态：共\s*(\d+)\s*张，已完成\s*(\d+)\s*张，待生成\s*(\d+)\s*张", msg)
    if m:
        return f"🎨 配图：共 {m.group(1)} 张，已完成 {m.group(2)} 张，待生成 {m.group(3)} 张。"
    m = re.search(r"正在使用\s*(.*?)\s*生成章节脚本", msg)
    if m:
        return f"🧠 生成脚本：{m.group(1).strip()}。"
    m = re.search(r"正在使用\s*(.*?)\s*单独润色", msg)
    if m:
        return f"🪶 润色台词：{m.group(1).strip()}。"
    m = re.search(r"文件夹后处理开始：.*?图片\s*(\d+)\s*张", msg)
    if m:
        return f"🖼️ 开始后处理图片：{m.group(1)} 张。"
    m = re.search(r"文件夹后处理完成：成功\s*(\d+)\s*张，失败\s*(\d+)\s*张", msg)
    if m:
        return f"✅ 后处理完成：成功 {m.group(1)} 张，失败 {m.group(2)} 张。"

    if COMPACT_LOG_SUPPRESS_RE.search(msg):
        return None
    if COMPACT_LOG_IMPORTANT_RE.search(msg):
        return msg
    return None


def should_suppress_log_message(message: str) -> bool:
    return compact_log_message_for_display(message) is None


def _detect_font_family_from_candidates(candidates, fallback: str, root=None) -> str:
    preferred = [x for x in candidates if x]
    try:
        import tkinter.font as tkfont
        families = set(tkfont.families(root=root))
        lower_map = {f.lower(): f for f in families}
        for name in preferred:
            found = lower_map.get(str(name).lower())
            if found:
                return found
    except Exception:
        pass
    return fallback


