def clear_generated_image_folder(images_dir: str, logger=None, *, include_raw_backup: bool = True) -> int:
    """清空某个配图目录里的已有图片和 raw 备份，用于强制重新绘制。"""
    if not images_dir:
        return 0
    os.makedirs(images_dir, exist_ok=True)
    removed = 0
    try:
        for name in list(os.listdir(images_dir)):
            path = os.path.join(images_dir, name)
            if os.path.isdir(path):
                if include_raw_backup and name == "_raw":
                    if safe_rmtree(path, logger=logger):
                        removed += 1
                continue
            if name.lower().endswith(IMAGE_FILE_EXTENSIONS):
                if safe_remove_file(path, logger=logger):
                    removed += 1
        if logger:
            logger(f"🧽 已清空旧配图：{images_dir}（删除 {removed} 项）。")
    except Exception as e:
        if logger:
            logger(f"⚠️ 清空旧配图失败：{str(e)[:120]}")
    return removed


