PROMPT_TEMPLATE_KEYS = ("script_generation", "voiceover_polish", "postprocess_requirements")
PROMPT_FRAGMENT_KEY_FILES = {
    "script_generation": "script_generation.md",
    "voiceover_polish": "voiceover_polish.md",
    "postprocess_requirements": "postprocess_requirements.json",
}


def load_prompt_fragment(name: str, fallback: str = "") -> str:
    """读取外置提示词片段；用于把所有可调提示词从 Python 逻辑中拆出来。"""
    safe = str(name or "").strip().replace("\\", "/").split("/")[-1]
    if not safe:
        return str(fallback or "")
    path = os.path.join(PROMPT_FRAGMENT_DIR, safe)
    try:
        if os.path.exists(path):
            text = open(path, "r", encoding="utf-8").read().strip()
            if text:
                return text
    except Exception:
        pass
    return str(fallback or "")


def render_prompt_fragment(name: str, values: dict | None = None, fallback: str = "") -> str:
    return render_prompt_template(load_prompt_fragment(name, fallback), values or {})



def builtin_prompt_templates() -> dict:
    """代码内置兜底模板。正常情况下，默认模板从外部 JSON 文件读取。"""
    return {
        "script_generation": DEFAULT_SCRIPT_GENERATION_USER_PROMPT,
        "voiceover_polish": DEFAULT_VOICEOVER_POLISH_USER_PROMPT,
        "postprocess_requirements": DEFAULT_POSTPROCESS_REQUIREMENTS,
    }


def _script_generation_template_needs_visual_upgrade(template: str) -> bool:
    """保留兼容入口：不再检测或改写脚本生成模板里的绘图提示词。"""
    return False


def _upgrade_visual_prompt_template_if_needed(templates: dict) -> dict:
    """不再自动升级/优化绘图提示词模板；用户配置原样保留。"""
    return dict(templates or {})


def _normalize_prompt_templates(data: dict | None, fallback: dict | None = None) -> dict:
    """只保留程序支持的两个提示词槽位；空字段用 fallback 回补。"""
    base = dict(fallback or builtin_prompt_templates())
    if isinstance(data, dict):
        for key in PROMPT_TEMPLATE_KEYS:
            value = data.get(key, "")
            if isinstance(value, str) and value.strip():
                base[key] = value.strip()
    # 外置片段优先，方便单独优化提示词而不改 Python 或 JSON。
    for key, filename in PROMPT_FRAGMENT_KEY_FILES.items():
        fragment = load_prompt_fragment(filename, "")
        if fragment.strip():
            base[key] = fragment.strip()
    return base


def _read_prompt_template_json(path: str) -> dict | None:
    try:
        if path and os.path.exists(path):
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
            return data if isinstance(data, dict) else None
    except Exception:
        return None
    return None


def _write_prompt_template_json(path: str, templates: dict, *, content_style: str | None = None) -> bool:
    try:
        payload = _normalize_prompt_templates(templates)
        if content_style:
            payload["_content_style"] = normalize_content_style(content_style)
        with open(path, "w", encoding="utf-8") as f:
            json.dump(payload, f, ensure_ascii=False, indent=2)
        return True
    except Exception:
        return False


def normalize_content_style(value: str | None) -> str:
    raw = str(value or "").strip()
    if raw in CONTENT_STYLE_OPTIONS:
        return raw
    lowered = raw.lower()
    if lowered in CONTENT_STYLE_ALIASES:
        return CONTENT_STYLE_ALIASES[lowered]
    if raw in CONTENT_STYLE_ALIASES:
        return CONTENT_STYLE_ALIASES[raw]
    return DEFAULT_CONTENT_STYLE


def get_active_content_style() -> str:
    """直接读取当前风格；多任务线程优先使用自己的风格，避免 3 本书并行时互相覆盖。"""
    try:
        runtime_style = getattr(runtime_context, "content_style", "")
        if runtime_style:
            return normalize_content_style(runtime_style)
    except Exception:
        pass
    try:
        if os.path.exists(MODEL_SCHEME_FILE):
            with open(MODEL_SCHEME_FILE, "r", encoding="utf-8") as f:
                data = json.load(f)
            if isinstance(data, dict):
                return normalize_content_style(data.get("content_style"))
    except Exception:
        pass
    return DEFAULT_CONTENT_STYLE


